import{_ as i,o as a,c as r,ae as t}from"./chunks/framework.Czhw_PXq.js";const g=JSON.parse('{"title":"股市趋势技术分析圣经 - 第8章：支撑与阻力","description":"深入讲解支撑与阻力位的形成原理、预测方法以及在实战交易中的应用技巧","frontmatter":{"title":"股市趋势技术分析圣经 - 第8章：支撑与阻力","description":"深入讲解支撑与阻力位的形成原理、预测方法以及在实战交易中的应用技巧","date":"2026-04-18","author":"技术分析研习社","tags":["支撑阻力","技术分析","交易策略","夏巴克","价格目标"],"category":"技术分析","cover":"/images/sta/chapter8-cover.jpg"},"headers":[],"relativePath":"posts/sta-chapter-8.md","filePath":"posts/sta-chapter-8.md"}'),o={name:"posts/sta-chapter-8.md"};function e(n,l,s,u,h,p){return a(),r("div",null,[...l[0]||(l[0]=[t('<h1 id="第8章-支撑与阻力" tabindex="-1">第8章：支撑与阻力 <a class="header-anchor" href="#第8章-支撑与阻力" aria-label="Permalink to &quot;第8章：支撑与阻力&quot;">​</a></h1><h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to &quot;引言&quot;">​</a></h2><p>在股票技术分析中，**支撑（Support）<strong>与</strong>阻力（Resistance）**是最实用也最重要的概念之一。夏巴克指出：&quot;支撑与阻力水平是本课程中最有趣，也最实际的研究主题之一。&quot;</p><p>支撑与阻力不仅帮助我们预测价格目标，还能提供明确的交易策略。本章将深入讲解支撑与阻力位的形成原理、预测方法以及在实战中的应用。</p><h2 id="一、支撑与阻力的基本概念" tabindex="-1">一、支撑与阻力的基本概念 <a class="header-anchor" href="#一、支撑与阻力的基本概念" aria-label="Permalink to &quot;一、支撑与阻力的基本概念&quot;">​</a></h2><h3 id="_1-1-定义" tabindex="-1">1.1 定义 <a class="header-anchor" href="#_1-1-定义" aria-label="Permalink to &quot;1.1 定义&quot;">​</a></h3><p><strong>阻力价位（Resistance）</strong>：</p><ul><li>股价上涨运动中被阻滞的价格区间</li><li>在该位置上股票的供给增加</li><li>也可被称作&quot;供给区&quot;</li></ul><p><strong>支撑价位（Support）</strong>：</p><ul><li>股价下跌过程中股价停留的区间</li><li>在该位置上股票的需求增加</li><li>也可被称作&quot;需求区&quot;</li></ul><h3 id="_1-2-角色转换原理" tabindex="-1">1.2 角色转换原理 <a class="header-anchor" href="#_1-2-角色转换原理" aria-label="Permalink to &quot;1.2 角色转换原理&quot;">​</a></h3><p><strong>关键规律</strong>：</p><ul><li>当一个由阻力形成的区域形态被突破后，它就变成了支撑位</li><li>当支撑价位被突破后，它成为以后股价运动的阻力位</li><li>支撑与阻力会不断交换身份</li></ul><p><strong>原理说明</strong>：</p><ul><li>过去的底部变为未来的顶部</li><li>过去的顶部变成新的底部</li></ul><h2 id="二、支撑与阻力的形成原因" tabindex="-1">二、支撑与阻力的形成原因 <a class="header-anchor" href="#二、支撑与阻力的形成原因" aria-label="Permalink to &quot;二、支撑与阻力的形成原因&quot;">​</a></h2><h3 id="_2-1-记忆因素的影响" tabindex="-1">2.1 记忆因素的影响 <a class="header-anchor" href="#_2-1-记忆因素的影响" aria-label="Permalink to &quot;2.1 记忆因素的影响&quot;">​</a></h3><p><strong>自然解释</strong>：</p><ul><li>公众等交易者倾向于记住并看重股价之前的走势</li><li>当股价在一个较窄的区域内波动了一段时间</li><li>公众的买卖交易都聚集在该区间内</li><li>因此人们容易记住这个特定的价位</li></ul><p><strong>重要规律</strong>：</p><ul><li>股价停留在该区间内时间越久</li><li>其间发生的交易量越大</li><li>这个区间对于未来技术分析就越重要</li></ul><h3 id="_2-2-人为因素的影响" tabindex="-1">2.2 人为因素的影响 <a class="header-anchor" href="#_2-2-人为因素的影响" aria-label="Permalink to &quot;2.2 人为因素的影响&quot;">​</a></h3><p><strong>内部人操作</strong>：</p><ul><li>职业操盘者计划好的行为</li><li>清楚自己想要在什么价位吸入股票</li><li>在什么价位抛出股票</li></ul><p><strong>操作策略</strong>：</p><ul><li>在100左右买入所需的大部分股票</li><li>决定在125左右卖出</li><li>第一次达到目标时先抛出约1/3的股票</li><li>让股价自己逐渐下跌</li><li>如果股价即将跌穿100，买回一些股票</li><li>新的上涨趋势再次接近125时，卖出剩余股票</li></ul><h3 id="_2-3-可靠程度评估" tabindex="-1">2.3 可靠程度评估 <a class="header-anchor" href="#_2-3-可靠程度评估" aria-label="Permalink to &quot;2.3 可靠程度评估&quot;">​</a></h3><p><strong>总体评价</strong>：</p><ul><li>支撑和阻力价位非常可靠</li><li>但并非万无一失</li><li>可能比之前学习的形态和法则更重要、更可靠</li></ul><p><strong>失效情况</strong>：</p><ul><li>历史走势中预测的阻力位和支撑位可能不会持续有效</li><li>一旦这些价位被打破，就在反面意义上起作用</li><li>证明当前股价运动的巨大力量</li><li>表明这次运动将一直持续到下一次阻力或支撑位出现</li></ul><h2 id="三、长期趋势中的支撑与阻力" tabindex="-1">三、长期趋势中的支撑与阻力 <a class="header-anchor" href="#三、长期趋势中的支撑与阻力" aria-label="Permalink to &quot;三、长期趋势中的支撑与阻力&quot;">​</a></h2><h3 id="_3-1-道琼斯工业平均指数案例" tabindex="-1">3.1 道琼斯工业平均指数案例 <a class="header-anchor" href="#_3-1-道琼斯工业平均指数案例" aria-label="Permalink to &quot;3.1 道琼斯工业平均指数案例&quot;">​</a></h3><p><strong>1924-1929年牛市中的阻力位</strong>：</p><ul><li>120-124：停留5个月</li><li>160-164：停留1年多</li><li>200：停留6个月</li><li>320-324：停留5个月</li></ul><p><strong>1929-1932年熊市中的支撑与阻力转换</strong>：</p><ul><li>196：1929年第一次恐慌性下跌的支撑位 → 1930年4月的阻力位</li><li>216：1928年早期上涨的阻力位 → 1930年的支撑位</li><li>160：1925-1927年的阻力位 → 1930年的支撑位 → 1931年的阻力位</li><li>120：1924年末的阻力位 → 1931年的支撑位 → 1931年的阻力位</li></ul><h3 id="_3-2-通用电气公司案例" tabindex="-1">3.2 通用电气公司案例 <a class="header-anchor" href="#_3-2-通用电气公司案例" aria-label="Permalink to &quot;3.2 通用电气公司案例&quot;">​</a></h3><p><strong>1929-1932年熊市</strong>：</p><p><strong>重要支撑位</strong>：</p><ul><li>42：1929年恐慌性下跌的支撑位</li><li>64-65：1929年末的阻力区 → 1930年的支撑位</li><li>54-55：1929年12月的支撑位</li><li>24-25：1931年的重要支撑位</li></ul><p><strong>重要阻力位</strong>：</p><ul><li>78-79：1930年阻力，持续一个半月</li><li>94-96：1930年阻力位</li></ul><p><strong>1932-1936年牛市中的转换</strong>：</p><ul><li>18：1932年上涨刺穿 → 1933-1934年持续影响</li><li>24-25：1931年的支撑 → 1933-1935年的阻力</li><li>42：1929年的支撑 → 1936年的阻力</li></ul><h2 id="四、中期趋势中的支撑与阻力" tabindex="-1">四、中期趋势中的支撑与阻力 <a class="header-anchor" href="#四、中期趋势中的支撑与阻力" aria-label="Permalink to &quot;四、中期趋势中的支撑与阻力&quot;">​</a></h2><h3 id="_4-1-微小顶部与底部的转换" tabindex="-1">4.1 微小顶部与底部的转换 <a class="header-anchor" href="#_4-1-微小顶部与底部的转换" aria-label="Permalink to &quot;4.1 微小顶部与底部的转换&quot;">​</a></h3><p><strong>典型案例：斯奈德包装公司</strong></p><p><strong>上涨过程中的支撑现象</strong>：</p><ul><li>7-8月：19遇到阻力 → 8月29日突破</li><li>反弹在21形成微小顶部 → 回落至19得到支撑</li><li>涨至23½ → 跌至21得到支撑</li><li>每次小幅下跌都在前面小幅上涨的顶部得到支撑</li></ul><p><strong>反转后的支撑与阻力</strong>：</p><ul><li>11月中期反转后</li><li>第一次剧烈下跌停滞在10月末微小顶部附近</li><li>第二次下跌在9月最后一周的顶部附近得到支撑</li></ul><h3 id="_4-2-判断标准" tabindex="-1">4.2 判断标准 <a class="header-anchor" href="#_4-2-判断标准" aria-label="Permalink to &quot;4.2 判断标准&quot;">​</a></h3><p><strong>对于中期趋势交易者</strong>：</p><ul><li>上涨过程中的微小支撑位被突破 → 没有负面意义</li><li>如果突破比较重要的支撑位 → 技术形势将发生重要变化</li><li>中期趋势很可能被反转</li></ul><h2 id="五、形态中的支撑与阻力" tabindex="-1">五、形态中的支撑与阻力 <a class="header-anchor" href="#五、形态中的支撑与阻力" aria-label="Permalink to &quot;五、形态中的支撑与阻力&quot;">​</a></h2><h3 id="_5-1-头肩形态" tabindex="-1">5.1 头肩形态 <a class="header-anchor" href="#_5-1-头肩形态" aria-label="Permalink to &quot;5.1 头肩形态&quot;">​</a></h3><p><strong>颈线的作用</strong>：</p><ul><li>突破点之后的颈线是走势图中非常关键的一条线</li><li>颈线第一次被突破表明趋势的反转</li><li>之后股价可能会回到颈线附近</li><li>但极少能显著地穿过</li></ul><p><strong>倾斜颈线</strong>：</p><ul><li>如果颈线呈水平，支撑或阻力水平容易解释</li><li>如果颈线向上或向下倾斜，功能更类似于趋势线</li></ul><h3 id="_5-2-矩形和直角三角形" tabindex="-1">5.2 矩形和直角三角形 <a class="header-anchor" href="#_5-2-矩形和直角三角形" aria-label="Permalink to &quot;5.2 矩形和直角三角形&quot;">​</a></h3><p><strong>矩形形态</strong>：</p><ul><li>上下边界分别代表阻力和支撑水平</li><li>突破后角色立即交换</li><li>上涨突破后，上边界变为支撑水平</li><li>下跌突破后，下边界变为阻力水平</li></ul><p><strong>直角三角形</strong>：</p><ul><li>上升三角形的上边线（水平边线）被突破后成为支撑线</li><li>下降三角形的下边线被突破后成为阻力线</li></ul><h3 id="_5-3-对称三角形" tabindex="-1">5.3 对称三角形 <a class="header-anchor" href="#_5-3-对称三角形" aria-label="Permalink to &quot;5.3 对称三角形&quot;">​</a></h3><p><strong>突破后的支撑与阻力</strong>：</p><ul><li>取决于突破发生时距离理论端点的距离</li><li>早期突破：形态边线的延长线成为支撑/阻力线</li><li>端点附近突破：端点水平成为支撑/阻力线</li></ul><p><strong>三种情况</strong>：</p><p><strong>情况一：早期突破后很快折返</strong></p><ul><li>回撤将在形态边线的延长线附近停住</li><li>向上突破：上边线成为支撑线</li><li>向下突破：下边线成为阻力线</li></ul><p><strong>情况二：突破后运动一段距离才折返</strong></p><ul><li>回撤一般在对称三角形的端点水平附近遇到阻力</li></ul><p><strong>情况三：运动相当长距离后才掉头</strong></p><ul><li>折返会停在三角形刚形成时的边线顶点水平上</li><li>股价已经离开了对称三角形的&quot;磁场&quot;区域</li></ul><h3 id="_5-4-支点-cradle" tabindex="-1">5.4 支点（Cradle） <a class="header-anchor" href="#_5-4-支点-cradle" aria-label="Permalink to &quot;5.4 支点（Cradle）&quot;">​</a></h3><p><strong>定义</strong>：</p><ul><li>两条趋势线相交时形成的交点</li><li>根据形状特征被称作&quot;支点&quot;</li></ul><p><strong>特点</strong>：</p><ul><li>形成更大的阻力</li><li>股价并不总是会折返到支点</li><li>但当这种情况真的出现时</li><li>股价运动总会在该点停止并掉头</li></ul><h2 id="六、缺口中的支撑与阻力" tabindex="-1">六、缺口中的支撑与阻力 <a class="header-anchor" href="#六、缺口中的支撑与阻力" aria-label="Permalink to &quot;六、缺口中的支撑与阻力&quot;">​</a></h2><h3 id="_6-1-突破缺口" tabindex="-1">6.1 突破缺口 <a class="header-anchor" href="#_6-1-突破缺口" aria-label="Permalink to &quot;6.1 突破缺口&quot;">​</a></h3><p><strong>特点</strong>：</p><ul><li>形成缺口的股价运动建立了一道支撑或阻力&quot;防线&quot;</li><li>阻挡之后的股价回到旧形态</li></ul><p><strong>支撑/阻力水平</strong>：</p><ul><li>上升突破缺口：缺口顶部附近水平得到支撑</li><li>下跌缺口：形成阻力水平</li></ul><h3 id="_6-2-调整缺口" tabindex="-1">6.2 调整缺口 <a class="header-anchor" href="#_6-2-调整缺口" aria-label="Permalink to &quot;6.2 调整缺口&quot;">​</a></h3><p><strong>特点</strong>：</p><ul><li>有时也具有支撑或阻力作用</li><li>如果缺口比较宽，顶部水平成为支撑</li><li>如果顶部水平支撑失败，中间或底部可能形成支撑</li><li>如果这些都失败，趋势将持续到下一个支撑水平</li></ul><h2 id="七、特殊价位的意义" tabindex="-1">七、特殊价位的意义 <a class="header-anchor" href="#七、特殊价位的意义" aria-label="Permalink to &quot;七、特殊价位的意义&quot;">​</a></h2><h3 id="_7-1-50、100等价位的特殊意义" tabindex="-1">7.1 50、100等价位的特殊意义 <a class="header-anchor" href="#_7-1-50、100等价位的特殊意义" aria-label="Permalink to &quot;7.1 50、100等价位的特殊意义&quot;">​</a></h3><p><strong>心理作用</strong>：</p><ul><li>整数关口往往具有心理支撑或阻力作用</li><li>50、100等整数价位尤其重要</li><li>交易者往往在这些价位设置买入或卖出指令</li></ul><h3 id="_7-2-中期运动的半途理论" tabindex="-1">7.2 中期运动的半途理论 <a class="header-anchor" href="#_7-2-中期运动的半途理论" aria-label="Permalink to &quot;7.2 中期运动的半途理论&quot;">​</a></h3><p><strong>原理</strong>：</p><ul><li>股价运动往往在半途位置遇到支撑或阻力</li><li>可以帮助预测价格目标</li></ul><h2 id="八、支撑与阻力的实战应用" tabindex="-1">八、支撑与阻力的实战应用 <a class="header-anchor" href="#八、支撑与阻力的实战应用" aria-label="Permalink to &quot;八、支撑与阻力的实战应用&quot;">​</a></h2><h3 id="_8-1-买入或卖出的第二次机会" tabindex="-1">8.1 买入或卖出的第二次机会 <a class="header-anchor" href="#_8-1-买入或卖出的第二次机会" aria-label="Permalink to &quot;8.1 买入或卖出的第二次机会&quot;">​</a></h3><p><strong>应用场景</strong>：</p><ul><li>错过第一次操作的机会</li><li>在仍然有利可图的水平上进行补操作</li></ul><p><strong>案例</strong>：</p><ul><li>股价上涨至突破形态时，由于某种原因没有买入</li><li>股价回跌至形态支撑线附近</li><li>获得第二次买入的良机</li></ul><h3 id="_8-2-避免过分担心" tabindex="-1">8.2 避免过分担心 <a class="header-anchor" href="#_8-2-避免过分担心" aria-label="Permalink to &quot;8.2 避免过分担心&quot;">​</a></h3><p><strong>应用场景</strong>：</p><ul><li>买入股票后看到股价回落到形态边线附近</li><li>通过支撑与阻力分析知道这是正常现象</li><li>只要股价在边线处得到支撑，对之前的判断仍然可以保持信心</li></ul><h3 id="_8-3-卖空操作中的应用" tabindex="-1">8.3 卖空操作中的应用 <a class="header-anchor" href="#_8-3-卖空操作中的应用" aria-label="Permalink to &quot;8.3 卖空操作中的应用&quot;">​</a></h3><p><strong>策略</strong>：</p><ul><li>在阻力位附近卖空</li><li>在支撑位附近平仓</li><li>设置止损位于阻力位的另一侧</li></ul><h2 id="九、本章总结" tabindex="-1">九、本章总结 <a class="header-anchor" href="#九、本章总结" aria-label="Permalink to &quot;九、本章总结&quot;">​</a></h2><p>本章我们深入学习了支撑与阻力：</p><ol><li><p><strong>基本概念</strong>：</p><ul><li>阻力：上涨中被阻滞的价格区间</li><li>支撑：下跌中停留的价格区间</li><li>角色转换：突破后支撑变阻力，阻力变支撑</li></ul></li><li><p><strong>形成原因</strong>：</p><ul><li>记忆因素：公众对历史价位的记忆</li><li>人为因素：内部人有计划的操作</li></ul></li><li><p><strong>长期趋势中的应用</strong>：</p><ul><li>过去的底部变为未来的顶部</li><li>过去的顶部变成新的底部</li><li>周线图比月线图更准确</li></ul></li><li><p><strong>形态中的应用</strong>：</p><ul><li>头肩形态：颈线的作用</li><li>矩形和直角三角形：边线的支撑阻力</li><li>对称三角形：三种情况的分析</li><li>支点：两条趋势线的交点</li></ul></li><li><p><strong>实战应用</strong>：</p><ul><li>提供第二次操作机会</li><li>避免过分担心正常回撤</li><li>卖空操作中的应用</li></ul></li></ol><p><strong>核心原则</strong>：</p><ul><li>支撑与阻力是非常可靠的技术工具</li><li>但并非万无一失</li><li>需要结合成交量和其他技术因素综合判断</li><li>一旦被突破，就在反面意义上起作用</li></ul><hr><p><strong>延伸阅读</strong>：</p><ul><li>第7章：趋势线与通道</li><li>第9章：均值测量理论</li><li>第10章：虚假移动与陷阱</li></ul><p><strong>免责声明</strong>：本文仅供学习交流使用，不构成投资建议。股市有风险，投资需谨慎。</p>',118)])])}const c=i(o,[["render",e]]);export{g as __pageData,c as default};
